



















import _ from 'lodash';
import {
  Component,
  Prop,
  Vue,
  Watch,
} from 'vue-property-decorator';
import {
  State,
  Action,
} from 'vuex-class';
import { CARD } from '@/interface/card';
import CardPopover from '@/components/CardPopover.vue';
import CardChoose from '@/components/CardChoose.vue';
import SimulatorAside from '@/components/SimulatorAside.vue';

@Component({
  components: {
  CardPopover,
  CardChoose,
  SimulatorAside,
  }
  })
export default class Simulator extends Vue {
  @Prop() private title!: string
  @Prop() private Items!: Array < object >
    @State private currentData!: Array < any >
    private chunkData!: Array < any >
    private data() {
      return {
        activeNames: ['1'],
        chunkData: undefined,
      };
    }
    @Watch('currentData')
    private changeCurrentData() {
      this.chunkData = _.chunk(this.currentData, 2);
    }
    private mounted() {
      this.chunkData = _.chunk(this.currentData, 2);
    }
    private handleChange(val: any) {
      console.log(val);
    }
}
