export const effectStr = (reslut: any): string => {
  let str = '';
  const arr = [
    'qi_xue',
    'zhen_qi',
    'gong_ji',
    'fang_yu',
    'ming_zhong',
    'duo_shan',
    'bao_ji_lv',
    'bao_ji_shang_hai',
    'xuan_yun',
    'xu_ruo',
    'ding_shen',
    'mei_huo',
    'hun_shui',
    'fu_jia_shang_hai',
    'jian_mian_pu_tong_shang_hai',
    'jian_bao_ji',
    'jian_bao_shang',
    'ji_neng_duo_shan',
    'ji_neng_ming_zhong',
    'jian_mian',
    'yu_xian',
    'yu_mo',
    'yu_fo',
    'wu_shi',
    'ke_xian',
    'ke_mo',
    'ke_fo',
    'xiu_wei',
    'yuan_li',
  ];
  _.forEach(arr, (key: propertyType) => {
    if (reslut[key] > 0) {
      str += `${formatStr(property[key], reslut[key])}<br/>`;
    }
  });
  return str;
};
