/* eslint-disable */
import _ from 'lodash'
import { 
  SET_CURRENTDATA,
  DELETE_CURRENTDATA, 
  SAVE_MY_CARD,
  SET_MY_CARD,
  SAVE_HOME_ACTIVE_NAME,
  SET_CALCULATOR_INITDATA,
  DELETE_CALCULATOR_INITDATA,
  SET_CALCULATOR_GENERALDATA,
  SET_CALCULATOR_EXTREMITYDATA,
} from './mutation-types';
import { State } from './state';

export default {
  [SAVE_HOME_ACTIVE_NAME](state: State, payload: any){
    state.homeActive = payload
  },
  [SET_CURRENTDATA](state: State, payload: any) {
    state.currentData = payload;
  },
  [DELETE_CURRENTDATA](state: State, payload: any) {
    const { currentData } = state
    const index = _.findIndex(currentData[payload.id], { name: payload.name })
    currentData[payload.id].splice(index, 1)
    state.currentData = currentData;
  },
  [SAVE_MY_CARD](state: State, payload: any) {
    state.myCard.push(payload)
  },
  [SET_MY_CARD](state: State, payload: any){
    state.myCard = payload
  },
  [SET_CALCULATOR_INITDATA](state: State, payload: any){
    const { calculator } = state
    const newData = {
      ...calculator,
      initData: payload,
      active: 1,
    }
    state.calculator = newData
  },
  [DELETE_CALCULATOR_INITDATA](state: State, payload: any){
    const { calculator: { initData } } = state
    const index = _.findIndex(initData[payload.id], { name: payload.name })
    initData[payload.id].splice(index, 1)
    state.calculator.initData = initData;
  },
  [SET_CALCULATOR_GENERALDATA](state: State, payload: any){
    const { calculator } = state
    const newData = {
      ...calculator,
      generalData: payload,
    }
    state.calculator = newData
  },
  [SET_CALCULATOR_EXTREMITYDATA](state: State, payload: any){
    const { calculator } = state
    const newData = {
      ...calculator,
      extremityData: payload,
    }
    state.calculator = newData
  },
};
/* eslint-disable */
